class GatewayConfig {
  constructor() {
    this.port = parseInt(process.env.GATEWAY_PORT || '3000', 10);
    this.host = process.env.GATEWAY_HOST || '0.0.0.0';
    this.configPath = process.env.GATEWAY_CONFIG || './gateway.config.json';
    this.routes = [];
    this.pluginConfigs = [];
    this.globalHeaders = {};
    this.rateLimit = {
      enabled: process.env.RATE_LIMIT_ENABLED === 'true',
      windowMs: parseInt(process.env.RATE_LIMIT_WINDOW_MS || '60000', 10),
      maxRequests: parseInt(process.env.RATE_LIMIT_MAX || '100', 10)
    };
  }

  load() {
    // Load from config file
    if (fs.existsSync(this.configPath)) {
      try {
        const raw = fs.readFileSync(this.configPath, 'utf-8');
        const config = JSON.parse(raw);
        this.routes = config.routes || [];
        this.pluginConfigs = config.plugins || [];
        this.globalHeaders = config.globalHeaders || {};

        if (config.port) this.port = config.port;
        if (config.host) this.host = config.host;
        if (config.rateLimit) {
          Object.assign(this.rateLimit, config.rateLimit);
        }

        console.log(`[Config] Loaded configuration from ${this.configPath}`);
      } catch (err) {
        console.error(`[Config] Failed to load config file: ${err.message}`);
      }
    } else {
      console.log(`[Config] No config file found at ${this.configPath}, using defaults`);
    }

    // Load plugin configs from environment variable
    if (process.env.GATEWAY_PLUGINS) {
      try {
        const envPlugins = JSON.parse(process.env.GATEWAY_PLUGINS);
        this.pluginConfigs = this.pluginConfigs.concat(envPlugins);
      } catch (err) {
        console.error(`[Config] Failed to parse GATEWAY_PLUGINS env var: ${err.message}`);
      }
    }

    // Load routes from environment variable
    if (process.env.GATEWAY_ROUTES) {
      try {
        const envRoutes = JSON.parse(process.env.GATEWAY_ROUTES);
        this.routes = this.routes.concat(envRoutes);
      } catch (err) {
        console.error(`[Config] Failed to parse GATEWAY_ROUTES env var: ${err.message}`);
      }
    }

    return this;
  }
}

