class GatewayContext {
  constructor(req, res) {
    this.req = req;
    this.res = res;
    this.startTime = Date.now();
    this.id = `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;

    // Parsed request info
    this.parsedUrl = url.parse(req.url, true);
    this.path = this.parsedUrl.pathname;
    this.query = this.parsedUrl.query;
    this.method = req.method;
    this.headers = { ...req.headers };
    this.body = null;
    this.rawBody = null;

    // Routing
    this.matchedRoute = null;
    this.params = {};

    // Response tracking
    this.statusCode = 200;
    this.responseHeaders = {};
    this.responseBody = null;
    this.responseSent = false;

    // Plugin data storage
    this.state = {};
    this.stopOnError = false;

    // Upstream response
    this.upstreamResponse = null;
    this.upstreamBody = null;

    // Client identification for rate limiting
    this.clientIp = req.headers['x-forwarded-for']?.split(',')[0]?.trim()
      || req.socket?.remoteAddress
      || 'unknown';
  }

  setHeader(name, value) {
    this.responseHeaders[name] = value;
  }

  setStatus(code) {
    this.statusCode = code;
  }

  send(statusCode, body, headers = {}) {
    if (this.responseSent) return;
    this.responseSent = true;

    const allHeaders = {
      'Content-Type': 'application/json',
      'X-Request-Id': this.id,
      'X-Response-Time': `${Date.now() - this.startTime}ms`,
      ...this.responseHeaders,
      ...headers
    };

    this.res.writeHead(statusCode, allHeaders);

    if (typeof body === 'object' && body !== null) {
      this.res.end(JSON.stringify(body));
    } else {
      this.res.end(body || '');
    }
  }
}

